-- Auto-generated from https://www.ctu.edu.vn/doi-ngu-giang-vien.html and staff.php pages 1-17
SET NOCOUNT ON;

DECLARE @FacultyId UNIQUEIDENTIFIER;
IF NOT EXISTS (SELECT 1 FROM faculties WHERE code = 'CTU')
BEGIN
    SET @FacultyId = NEWID();
END
ELSE
BEGIN
    SELECT @FacultyId = id FROM faculties WHERE code = 'CTU';
END

DECLARE @LecturerSource TABLE (
    full_name NVARCHAR(255) NOT NULL,
    gender NVARCHAR(5) NULL,
    rank_title NVARCHAR(50) NULL,
    degree_title NVARCHAR(50) NULL,
    specialization NVARCHAR(255) NULL
);


;WITH DistinctSpecialization AS (
    SELECT DISTINCT specialization
    FROM @LecturerSource
    WHERE specialization IS NOT NULL AND LTRIM(RTRIM(specialization)) <> ''
), RankedSpecialization AS (
    SELECT specialization, ROW_NUMBER() OVER (ORDER BY specialization) AS rn
    FROM DistinctSpecialization
)
SELECT NEWID(), specialization, CONCAT('CTUS', RIGHT('0000' + CAST(rn AS VARCHAR(4)), 4)), @FacultyId
FROM RankedSpecialization;

;WITH LecturerRows AS (
    SELECT full_name, specialization, ROW_NUMBER() OVER (ORDER BY full_name, specialization) AS rn
    FROM @LecturerSource
)
SELECT NEWID(), CONCAT('CTU', RIGHT('0000' + CAST(lr.rn AS VARCHAR(4)), 4)),
       lr.full_name,
       @FacultyId,
       s.id,
       'ACTIVE'
FROM LecturerRows lr
LEFT JOIN subjects s
    ON s.name = lr.specialization AND s.faculty_id = @FacultyId;

DECLARE @ImportedCount INT;
SELECT @ImportedCount = COUNT(*) FROM @LecturerSource;
PRINT CONCAT('Imported lecturers: ', CAST(@ImportedCount AS VARCHAR(20)));
